import React, { useState } from "react";
import { useCart } from "./CartContext";

function Help() {
  const {
    cartItems,
    addToCart,
    increaseQty,
    decreaseQty
  } = useCart();

  const [activeService, setActiveService] = useState(null);

  const services = [
    "Medicines",
    "Groceries",
    "Emergency",
    "Food Delivery",
    "Transport"
  ];

  const medicines = [
    { id: 1, name: "Paracetamol", desc: "Fever & pain relief" },
    { id: 2, name: "Ibuprofen", desc: "Pain & inflammation" },
    { id: 3, name: "Amoxicillin", desc: "Antibiotic" },
    { id: 4, name: "Cetirizine", desc: "Allergy relief" },
    { id: 5, name: "Vitamin C", desc: "Immunity booster" }
  ];

  const getQty = (id) => {
    const item = cartItems.find((i) => i.id === id);
    return item ? item.quantity : 0;
  };

  return (
    <div className="help-container">

      <h2>Select Service</h2>

      {/* 🔥 SERVICES HORIZONTAL */}
      <div className="services-row">
        {services.map((service) => (
          <div
            key={service}
            className={`service-box ${
              activeService === service ? "active" : ""
            }`}
            onClick={() => {
              if (service === "Medicines") {
                setActiveService(service);
              } else {
                alert(service + " is under maintenance 🚧");
              }
            }}
          >
            {service}
          </div>
        ))}
      </div>

      {/* 💊 MEDICINES VIEW */}
      {activeService === "Medicines" && (
        <>
          <h2 style={{ marginTop: "25px" }}>Medicines</h2>

          <div className="medicine-vertical">
            {medicines.map((med) => {
              const qty = getQty(med.id);

              return (
                <div key={med.id} className="medicine-card">

                  <div>
                    <h4>{med.name}</h4>
                    <p>{med.desc}</p>
                  </div>

                  {qty === 0 ? (
                    <button
                      className="add-btn"
                      onClick={() => addToCart(med)}
                    >
                      Add
                    </button>
                  ) : (
                    <div className="qty-controls">
                      <button onClick={() => decreaseQty(med.id)}>-</button>
                      <span>{qty}</span>
                      <button
                        onClick={() => increaseQty(med.id)}
                        disabled={qty >= 5}
                      >
                        +
                      </button>
                    </div>
                  )}

                </div>
              );
            })}
          </div>
        </>
      )}

    </div>
  );
}

export default Help;
